import random
from datetime import datetime, timedelta

def fn_collect_metrics():
    """
    采集日报指标数据。
    返回: {
        "has_data": bool,
        "metrics": dict or None,
        "collected_at": str
    }
    """
    # 模拟采集数据，实际项目中可替换为真实数据源
    today = datetime.now().strftime("%Y-%m-%d")

    # 模拟：有一定概率没有数据（比如节假日）
    has_data = random.random() > 0.3

    if has_data:
        metrics = {
            "date": today,
            "active_users": random.randint(100, 5000),
            "new_orders": random.randint(10, 300),
            "revenue": round(random.uniform(1000, 50000), 2),
            "conversion_rate": round(random.uniform(0.01, 0.15), 4)
        }
    else:
        metrics = None

    return {
        "has_data": has_data,
        "metrics": metrics,
        "collected_at": datetime.now().isoformat()
    }
"}

